MOD = 998244353

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    M = int(data[1])
    S = data[2]

    # Initialize DP table: dp[m][i][l] = number of ways to form a string of length m with LCS l using first i characters of S
    # Since M can be up to 100 and N is small (<=10), we use a 3D list
    dp = [[[0] * (N + 1) for _ in range(N + 1)] for _ in range(M + 1)]
    dp[0][0][0] = 1

    for m in range(M):
        for i in range(N + 1):
            for l in range(N + 1):
                if dp[m][i][l] == 0:
                    continue
                # Try all possible characters (a-z)
                for ch in range(26):
                    # Check if this character can extend the LCS
                    found = False
                    for j in range(i, N):
                        if ord(S[j]) - ord('a') == ch:
                            # This character matches S[j], so the LCS increases by 1
                            dp[m + 1][j + 1][l + 1] = (dp[m + 1][j + 1][l + 1] + dp[m][i][l]) % MOD
                            found = True
                            break
                    if not found:
                        # The character does not match any remaining character in S, LCS remains the same
                        dp[m + 1][i][l] = (dp[m + 1][i][l] + dp[m][i][l]) % MOD

    # Sum all possibilities for each k
    ans = [0] * (N + 1)
    for i in range(N + 1):
        for l in range(N + 1):
            ans[l] = (ans[l] + dp[M][i][l]) % MOD

    print(' '.join(map(str, ans)))

if __name__ == "__main__":
    main()
